import os

def get_ls_result(dir_path: str) -> str:
    try:
        # Validate the directory path to prevent directory traversal
        if not os.path.isdir(dir_path):
            return ''
        # Use os.listdir to get the files in the directory
        files = os.listdir(dir_path)
        # For each file, get detailed info (this is a simplified example)
        result = []
        for file in files:
            file_path = os.path.join(dir_path, file)
            stat = os.stat(file_path)
            result.append(f"{file} {stat.st_size} {stat.st_mtime}")
        return '\n'.join(result)
    except Exception:
        return ''

